This is not an accurate score, it is a heuristic only for the greedy LZ77
implementation. More accurate cost models are employed later. Making this
heuristic more accurate may hurt rather than improve compression.

The two direct uses of this heuristic are:
-avoid using a length of 3 in combination with a long distance. This only has
an effect if length == 3.
-make a slightly better choice between the two options of the lazy matching.

Indirectly, this affects:
-the block split points if the default of block splitting first is used, in a
rather unpredictable way
-the first zopfli run, so it affects the chance of the first run being closer
to the optimal output
*/
static int GetLengthScore(int length, int distance)
/* Pure heuristic with no side effects. */
__CPROVER_assigns()
/* Match lengths and distances are bounded by the LZ77 window in every caller
   (lengths fit in [0, ZOPFLI_MAX_MATCH], distances in [0, ZOPFLI_WINDOW_SIZE]);
   these bounds keep the length-1 arithmetic well inside int range. */
__CPROVER_requires(length >= 0 && length <= 258)
__CPROVER_requires(distance >= 0 && distance <= 32768)
/* Exact value: pins the comparison threshold (1024), its direction (>), and the
   length-1 penalty, so any mutation of the comparison operator or of the
   penalty arithmetic produces an observably different result. */
__CPROVER_ensures(__CPROVER_return_value == (distance > 1024 ? length - 1 : length))
/* The score is the raw length, optionally reduced by exactly one. */
__CPROVER_ensures(__CPROVER_return_value == length || __CPROVER_return_value == length - 1)
__CPROVER_ensures(__CPROVER_return_value <= length)
{
    /*
    At 1024, the distance uses 9+ extra bits and this seems to be the sweet spot
    on tested files.
    */
    return distance > 1024 ? length - 1 : length;
}

/*
Does LZ77 using an algorithm similar to gzip, with lazy matching, rather than
with the slow but better "squeeze" implementation.
The result is placed in the ZopfliLZ77Store.
If instart is larger than 0, it uses values before instart as starting
dictionary.
*/
void ZopfliLZ77Greedy(ZopfliBlockState *s, const unsigned char *in,
                      size_t instart, size_t inend,
                      ZopfliLZ77Store *store, ZopfliHash *h)
/* The block state, the rolling hash and its seven chain/value tables, the
   output store and its seven parallel buffers, and the input window are all
   live, distinct objects.  The greedy parse walks the input once, so instart
   never exceeds inend, and the input is readable over [0, inend) (it is indexed
   directly as in[i] and in[i - 1] when emitting literals). */
__CPROVER_requires(__CPROVER_is_fresh(s, sizeof(*s)))
__CPROVER_requires(__CPROVER_is_fresh(h, sizeof(*h)))
__CPROVER_requires(__CPROVER_is_fresh(h->head, sizeof(int)))
__CPROVER_requires(__CPROVER_is_fresh(h->prev, sizeof(unsigned short)))
__CPROVER_requires(__CPROVER_is_fresh(h->hashval, sizeof(int)))
__CPROVER_requires(__CPROVER_is_fresh(h->same, sizeof(unsigned short)))
__CPROVER_requires(__CPROVER_is_fresh(h->head2, sizeof(int)))
__CPROVER_requires(__CPROVER_is_fresh(h->prev2, sizeof(unsigned short)))
__CPROVER_requires(__CPROVER_is_fresh(h->hashval2, sizeof(int)))
__CPROVER_requires(__CPROVER_is_fresh(store, sizeof(*store)))
__CPROVER_requires(__CPROVER_is_fresh(store->litlens, sizeof(unsigned short)))
__CPROVER_requires(__CPROVER_is_fresh(store->dists, sizeof(unsigned short)))
__CPROVER_requires(__CPROVER_is_fresh(store->pos, sizeof(size_t)))
__CPROVER_requires(__CPROVER_is_fresh(store->ll_symbol, sizeof(unsigned short)))
__CPROVER_requires(__CPROVER_is_fresh(store->d_symbol, sizeof(unsigned short)))
__CPROVER_requires(__CPROVER_is_fresh(store->ll_counts, sizeof(size_t)))
__CPROVER_requires(__CPROVER_is_fresh(store->d_counts, sizeof(size_t)))
__CPROVER_requires(instart <= inend)
__CPROVER_requires(__CPROVER_is_fresh(in, inend * sizeof(*in)))
/* Frame: the parse mutates only the rolling-hash state (via the hash callees)
   and the output store (via ZopfliStoreLitLenDist).  Both are given as whole
   objects since the exact slots touched depend on the data-driven trip count. */
__CPROVER_assigns(h->val, h->val2,
                  __CPROVER_object_whole(h->head), __CPROVER_object_whole(h->prev),
                  __CPROVER_object_whole(h->hashval), __CPROVER_object_whole(h->same),
                  __CPROVER_object_whole(h->head2), __CPROVER_object_whole(h->prev2),
                  __CPROVER_object_whole(h->hashval2))
__CPROVER_assigns(store->size,
                  __CPROVER_object_whole(store->litlens), __CPROVER_object_whole(store->dists),
                  __CPROVER_object_whole(store->pos), __CPROVER_object_whole(store->ll_symbol),
                  __CPROVER_object_whole(store->d_symbol), __CPROVER_object_whole(store->ll_counts),
                  __CPROVER_object_whole(store->d_counts))
{
    size_t i = 0, j;
    unsigned short leng;
    unsigned short dist;
    int lengthscore;
    size_t windowstart = instart > ZOPFLI_WINDOW_SIZE
                             ? instart - ZOPFLI_WINDOW_SIZE
                             : 0;
    unsigned short dummysublen[259];

    /* Lazy matching. */
    unsigned prev_length = 0;
    unsigned prev_match = 0;
    int prevlengthscore;
    int match_available = 0;

    if (instart == inend)
        return;

    ZopfliResetHash(ZOPFLI_WINDOW_SIZE, h);
    ZopfliWarmupHash(in, windowstart, inend, h);
    for (i = windowstart; i < instart; i++)
    {
        ZopfliUpdateHash(in, i, inend, h);
    }

    for (i = instart; i < inend; i++)
    {
        ZopfliUpdateHash(in, i, inend, h);

        ZopfliFindLongestMatch(s, h, in, i, inend, ZOPFLI_MAX_MATCH, dummysublen,
                               &dist, &leng);
        lengthscore = GetLengthScore(leng, dist);

